package com.agrios.platform.tasks.domain;
import jakarta.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="recurring_task_schedule",schema="tasks") public class RecurringTaskScheduleEntity {
 @Id private UUID id; @Column(nullable=false)private UUID tenantId; @Column(nullable=false)private String ownerContext; @Column(nullable=false)private UUID ownerEntityId; private UUID cropCycleId; @Column(nullable=false)private String taskType; @Column(nullable=false)private String title; @Column(columnDefinition="text")private String description; @Column(nullable=false)private String priority; private UUID assignedTo; @Column(nullable=false)private String recurrenceType; @Column(nullable=false)private int intervalValue; @Column(nullable=false)private Instant startAt; @Column(nullable=false)private Instant nextRunAt; private Instant endAt; @Column(nullable=false)private boolean active; @Version private long version; @Column(nullable=false)private Instant createdAt; private UUID createdBy; @Column(nullable=false)private Instant updatedAt; private UUID updatedBy; protected RecurringTaskScheduleEntity(){}
 public static RecurringTaskScheduleEntity create(UUID tenant,String ownerContext,UUID ownerId,UUID cycleId,String type,String title,String description,String priority,UUID assigned,String recurrence,int interval,Instant start,Instant end,UUID actor){var v=new RecurringTaskScheduleEntity();v.id=UUID.randomUUID();v.tenantId=tenant;v.ownerContext=ownerContext;v.ownerEntityId=ownerId;v.cropCycleId=cycleId;v.taskType=type;v.title=title;v.description=description;v.priority=priority;v.assignedTo=assigned;v.recurrenceType=recurrence;v.intervalValue=interval;v.startAt=start;v.nextRunAt=start;v.endAt=end;v.active=true;v.createdAt=Instant.now();v.updatedAt=v.createdAt;v.createdBy=actor;v.updatedBy=actor;return v;}
 public void advance(UUID actor){nextRunAt=switch(recurrenceType){case "DAILY"->nextRunAt.plusSeconds(86400L*intervalValue);case "WEEKLY"->nextRunAt.plusSeconds(604800L*intervalValue);case "MONTHLY"->nextRunAt.atZone(java.time.ZoneOffset.UTC).plusMonths(intervalValue).toInstant();default->throw new IllegalStateException("Unsupported recurrence.");};if(endAt!=null&&nextRunAt.isAfter(endAt))active=false;updatedAt=Instant.now();updatedBy=actor;}
 public UUID id(){return id;} public UUID tenantId(){return tenantId;} public String ownerContext(){return ownerContext;} public UUID ownerEntityId(){return ownerEntityId;} public UUID cropCycleId(){return cropCycleId;} public String taskType(){return taskType;} public String title(){return title;} public String description(){return description;} public String priority(){return priority;} public UUID assignedTo(){return assignedTo;} public String recurrenceType(){return recurrenceType;} public int intervalValue(){return intervalValue;} public Instant nextRunAt(){return nextRunAt;} public Instant endAt(){return endAt;} public boolean active(){return active;} public long version(){return version;}
}
